import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, PointElement, LineElement, Title, Tooltip, Legend);

const PriceAnalytics = () => {
  const [productData, setProductData] = useState([]);
  const [categoryData, setCategoryData] = useState([]);
  const [range, setRange] = useState("weekly");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchTrends();
  }, [range]);

  const fetchTrends = async () => {
    setLoading(true);
    try {
      const [prodRes, catRes] = await Promise.all([
        axios.get(`http://localhost:7000/api/price-report/trends?type=product&range=${range}`),
        axios.get(`http://localhost:7000/api/price-report/trends?type=category&range=${range}`),
      ]);

      console.log("📊 Product Data:", prodRes.data);
      console.log("📊 Category Data:", catRes.data);

      setProductData(prodRes.data || []);
      setCategoryData(catRes.data || []);
    } catch (err) {
      console.error("Error fetching trends:", err);
    } finally {
      setLoading(false);
    }
  };

  const lineChartData = {
    labels:
      productData.length > 0
        ? [...new Set(productData.flatMap((d) => d.prices.map((p) => p.date)))]
        : [],
    datasets:
      productData.length > 0
        ? productData.map((p, i) => ({
            label: p._id,
            data: p.prices.map((pr) => pr.avgPrice),
            borderColor: `hsl(${i * 45}, 70%, 50%)`,
            backgroundColor: `hsl(${i * 45}, 70%, 60%, 0.2)`,
            tension: 0.3,
            fill: false,
          }))
        : [],
  };

  const barChartData = {
    labels:
      categoryData.length > 0
        ? [...new Set(categoryData.flatMap((d) => d.prices.map((p) => p.date)))].sort()
        : [],
    datasets:
      categoryData.length > 0
        ? categoryData.map((c, i) => ({
            label: c._id,
            data: c.prices.map((pr) => pr.avgPrice),
            backgroundColor: `hsl(${i * 60}, 70%, 60%)`,
          }))
        : [],
  };

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h2 className="text-2xl font-bold mb-6 text-center text-gray-800">
        📊 Price Analytics Dashboard
      </h2>

      <div className="flex justify-center mb-6">
        <select
          value={range}
          onChange={(e) => setRange(e.target.value)}
          className="border p-2 rounded-md bg-white shadow"
        >
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
        </select>
      </div>

      {loading ? (
        <div className="text-center text-gray-500 text-lg">Loading analytics...</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-white shadow-lg p-4 rounded-2xl">
            <h3 className="text-lg font-semibold mb-3 text-center text-gray-700">
              📈 Product-wise Price Trends
            </h3>
            {lineChartData.labels.length > 0 ? (
              <Line
                data={lineChartData}
                options={{
                  responsive: true,
                  plugins: { legend: { position: "bottom" } },
                  scales: { y: { beginAtZero: true } },
                }}
              />
            ) : (
              <p className="text-center text-gray-400">No data available</p>
            )}
          </div>

          <div className="bg-white shadow-lg p-4 rounded-2xl">
            <h3 className="text-lg font-semibold mb-3 text-center text-gray-700">
              📉 Category-wise Price Trends
            </h3>
            {barChartData.labels.length > 0 ? (
              <Bar
                data={barChartData}
                options={{
                  responsive: true,
                  plugins: { legend: { position: "bottom" } },
                  scales: { y: { beginAtZero: true } },
                }}
              />
            ) : (
              <p className="text-center text-gray-400">No data available</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default PriceAnalytics;
